import math

t = int(input())
for _ in range(t):
    n = int(input())
    a = list(map(int, input().split()))

    best = float('inf')
    for x in range(3):
        for y in range(3):
            z = 0
            valid = True
            for ai in a:
                # need p<=x, q<=y, r>=0: p+2q+3r=ai
                min_r = float('inf')
                for p in range(x+1):
                    for q in range(y+1):
                        rem = ai - p - 2*q
                        if rem >= 0 and rem % 3 == 0:
                            r = rem // 3
                            if r < min_r:
                                min_r = r
                if min_r == float('inf'):
                    valid = False
                    break
                z = max(z, min_r)
            if valid:
                best = min(best, x + y + z)
    print(best)

